#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int maximalRectangle(vector<int>& heights) {
        stack<int> st;
        int max_area = 0;
        heights.insert(heights.begin(), 0);
        heights.push_back(0);
        for (int i = 0; i < heights.size(); i++) {
            while (!st.empty() && heights[st.top()] > heights[i]) {
                int h = heights[st.top()]; st.pop();
                int w = i - st.top() - 1;
                max_area = max(max_area, h * w);
            }
            st.push(i);
        }
        return max_area;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> heights(n);
    for (int i = 0; i < n; i++) cin >> heights[i];
    Solution sol;
    int ans = sol.maximalRectangle(heights);
    cout << ans << "\n";
    return 0;
}
